var e=[{id:`L7_1`,type:`dialog`,speaker:`STINGER_FOX_BOSS_NULL`,text:{KOREA:`크읏, 대체 뭐냐!`,JPN:`くうっ、いったい何なんだ！`,ENG:`Ugh, what the hell?`,TWN:`呃，怎麼回事！`},stage:{bg:`BLACK`,slots:{L:null,C:{char_id:`STINGER_FOX_BOSS_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`STINGER_FOX_BOSS_NULL`,text:{KOREA:`분명 제대로 조준했을 텐데, 어째서 저 꼬맹인 한 대도 맞질 않는 거지?`,JPN:`しっかり照準を合わせてるのに、なぜあのチビにはまったく当たらないんだ！？`,ENG:`Why can't I hit her, no matter how carefully I aim?`,TWN:`我明明瞄準好了，為什麼就是打不到那個小鬼？`},stage:{bg:`BLACK`,slots:{L:null,C:{char_id:`STINGER_FOX_BOSS_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`SIGMA_RAS_NULL_NULL`,text:{KOREA:`흐흥~ 그 정도로는 내 옷깃도 건드릴 수 없을 텐데.`,JPN:`ふふーんだ。その程度じゃ私の襟にも届かないよ？`,ENG:`Heh, you can't even leave a scratch on me doing that.`,TWN:`哼～就憑這種程度是打不到我的喔。`},stage:{bg:`HANGAR`,slots:{L:null,C:{char_id:`SIGMA_RAS_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`SIGMA_RAS_NULL_NULL`,text:{KOREA:`어때? 이제 내 대단함을 알겠어?`,JPN:`どう？　私のスゴさ、わかったでしょ？`,ENG:`Say, do you know how great I am now?`,TWN:`怎麼樣？知道我有多厲害了吧？`},stage:{bg:`HANGAR`,slots:{L:null,C:{char_id:`SIGMA_RAS_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`STINGER_FOX_BOSS_NULL`,text:{KOREA:`......그래, 그랬군.`,JPN:`……そうか、そうだったのか。`,ENG:`Yes, I see.`,TWN:`……是嗎，原來如此。`},stage:{bg:`HANGAR`,slots:{L:null,C:{char_id:`STINGER_FOX_BOSS_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`STINGER_FOX_BOSS_NULL`,text:{KOREA:`너 이 자식! 날 속였구나! 이건 홀로그램일 뿐이잖아!`,JPN:`てめえ、俺を騙してやがったな！　これはただの
ホログラムじゃないか！`,ENG:`You little demon! You fooled me! This is just a hologram!`,TWN:`你這傢伙！你騙我！你只是全息影像而已！`},stage:{bg:`HANGAR`,slots:{L:null,C:{char_id:`STINGER_FOX_BOSS_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`SIGMA_RAS_NULL_NULL`,text:{KOREA:`하하, 이제 알아챈 거야?`,JPN:`アハハ、今頃気付いたの？`,ENG:`Teehee! Now you know.`,TWN:`哈哈，你才發現嗎？`},stage:{bg:`HANGAR`,slots:{L:null,C:{char_id:`SIGMA_RAS_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`SIGMA_RAS_NULL_NULL`,text:{KOREA:`그치만 이미 속을대로 속았지롱~? 내 친구들은 이미 다 풀려났는걸?`,JPN:`でも、もう遅いんだよーんだ。私の仲間は全員
解放されたんだから。`,ENG:`But it's too late now. All my friends have gotten away from you.`,TWN:`可惜已經太晚了～我的朋友們已經被救出來了。`},stage:{bg:`HANGAR`,slots:{L:null,C:{char_id:`SIGMA_RAS_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`STINGER_FOX_BOSS_NULL`,text:{KOREA:`잘난 체 하는 것도 거기까지다!`,JPN:`調子に乗るのもそこまでだ！`,ENG:`I'm tired of your arrogance!`,TWN:`別高興地太早！`},stage:{bg:`HANGAR`,slots:{L:null,C:{char_id:`STINGER_FOX_BOSS_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`STINGER_FOX_BOSS_NULL`,text:{KOREA:`함선에 손상이 갈 것 같아서 일부러 출력을 조절하고 있었다만......`,JPN:`艦船を傷つけそうで、あえて力を加減していたが……`,ENG:`I didn't go all out because I didn't want to damage my ship,`,TWN:`我是因為怕影響到艦船才故意調整了功率……`},stage:{bg:`HANGAR`,slots:{L:null,C:{char_id:`STINGER_FOX_BOSS_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`STINGER_FOX_BOSS_NULL`,text:{KOREA:`이렇게 된 이상, 여길 모조리 불바다로 만들어주마!`,JPN:`こうなった以上、ここを火の海にしてやる！`,ENG:`but I don't care anymore. I'm going to set it on fire along with everything in it!`,TWN:`不過事已至此，我就把這裡燒成火海！`},stage:{bg:`HANGAR`,slots:{L:null,C:{char_id:`STINGER_FOX_BOSS_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`STINGER_FOX_BOSS_NULL`,text:{KOREA:`네 기계친구들이 양초처럼 녹은 뒤에도 그렇게 웃을 수 있는지 두고 보지!`,JPN:`お前の機械仲間がロウソクのように溶けても
笑っていられるか、見てやろうじゃないか！`,ENG:`Let's see if you still can laugh after all your friends turn into pools of molten metal!`,TWN:`等你的機械朋友都像蠟燭一樣融化掉之後，我看你還能不能笑得出來！`},stage:{bg:`HANGAR`,slots:{L:null,C:{char_id:`STINGER_FOX_BOSS_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`TITAN_FAW_NULL_NULL`,text:{KOREA:`이런! 위험하네! 내 뒤로 피하게나!`,JPN:`ハッ！　危険だ！　吾輩の後ろに隠れたまえ！`,ENG:`Oh, no! This is dangerous! Get behind me!`,TWN:`啊！危險！快躲到我身後！`},stage:{bg:`HANGAR`,slots:{L:null,C:{char_id:`SIGMA_RAS_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L30_1`,type:`dialog`,speaker:`SIGMA_RAS_NULL_NULL`,text:{KOREA:`괘, 괜찮아, 할아버지?`,JPN:`だ、大丈夫？　おじいちゃん？`,ENG:`G-Grandpa, are you okay?`,TWN:`沒、沒事嗎，爺爺？`},stage:{bg:`HANGAR`,slots:{L:null,C:{char_id:`SIGMA_RAS_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}}];export{e as default};